/**
 * 🧹 Cleanup Jobs
 * Auto-generated by Backend Factory
 */

import { pool } from '../db/pg.js';
import { registerCronJob } from './cronService.js';

/**
 * Clean up old events (older than 90 days)
 */
registerCronJob('cleanup:events', {
  interval: '1d',
  description: 'Delete events older than 90 days',
  handler: async () => {
    const t = await pool.query("SELECT to_regclass('public.events') AS t");
    if (!t.rows[0].t) return { deleted: 0, table: 'events', skipped: 'table not present' };
    const { rowCount } = await pool.query(
      "DELETE FROM events WHERE created_at < NOW() - INTERVAL '90 days'"
    );
    return { deleted: rowCount, table: 'events' };
  },
});

