/**
 * Log database table sizes (monitoring)
 */
registerCronJob('monitor:db-stats', {
  interval: '6h',
  description: 'Log database table sizes for monitoring',
  handler: async () => {
    const counts = {};
    try {
      const r = await pool.query('SELECT COUNT(*) as c FROM attachments');
      counts.attachments = parseInt(r.rows[0].c);
    } catch (e) { counts.attachments = 'error'; }
    try {
      const r = await pool.query('SELECT COUNT(*) as c FROM comments');
      counts.comments = parseInt(r.rows[0].c);
    } catch (e) { counts.comments = 'error'; }
    try {
      const r = await pool.query('SELECT COUNT(*) as c FROM invites');
      counts.invites = parseInt(r.rows[0].c);
    } catch (e) { counts.invites = 'error'; }
    try {
      const r = await pool.query('SELECT COUNT(*) as c FROM projects');
      counts.projects = parseInt(r.rows[0].c);
    } catch (e) { counts.projects = 'error'; }
    try {
      const r = await pool.query('SELECT COUNT(*) as c FROM subscriptions');
      counts.subscriptions = parseInt(r.rows[0].c);
    } catch (e) { counts.subscriptions = 'error'; }
    try {
      const r = await pool.query('SELECT COUNT(*) as c FROM tasks');
      counts.tasks = parseInt(r.rows[0].c);
    } catch (e) { counts.tasks = 'error'; }
    // #18: the raw per-table totals are PLATFORM-WIDE (cron has no tenant context).
    // Keep them in server-side ops logs only; the value returned here is persisted to
    // the tenant-accessible admin cron log, so it must NOT leak cross-tenant counts.
    console.log('📊 DB Stats (platform ops):', JSON.stringify(counts));
    return { ok: true, monitoredTables: Object.keys(counts).length, loggedAt: new Date().toISOString() };
  },
});

/**
 * Heartbeat — log that server is alive
 */
registerCronJob('heartbeat', {
  interval: '5m',
  description: 'Log server heartbeat for uptime monitoring',
  handler: async () => {
    const mem = process.memoryUsage();
    return {
      uptime: Math.floor(process.uptime()) + 's',
      heapMB: Math.round(mem.heapUsed / 1024 / 1024),
      rssMB: Math.round(mem.rss / 1024 / 1024),
    };
  },
});
